claude/agentpost/hooks/hooks.json:
{
  "hooks": {
    "SessionStart": [
      {
        "hooks": [
          {
            "type": "command",
            "command": "agentpost internal-claude-boundary idle"
          }
        ]
      }
    ],
    "UserPromptSubmit": [
      {
        "hooks": [
          {
            "type": "command",
            "command": "agentpost internal-claude-boundary busy"
          }
        ]
      }
    ],
    "Stop": [
      {
        "hooks": [
          {
            "type": "command",
            "command": "agentpost internal-claude-boundary idle --delay 1.0"
          }
        ]
      }
    ],
    "StopFailure": [
      {
        "hooks": [
          {
            "type": "command",
            "command": "agentpost internal-claude-boundary idle --delay 1.0"
          }
        ]
      }
    ]
  }
}

